def main():
    service = MongoJavaScriptQueryService()
    
    print("Advanced MongoDB Data Filtering Service")
    print("=" * 50)
    
    collection_name = input("Enter collection name (default: employees): ").strip() or "employees"
    service.set_collection(collection_name)
    
    choice = input("Insert sample data? (y/n): ").strip().lower()
    if choice == 'y':
        count = service.insert_sample_data(collection_name)
        print(f"Inserted {count} sample documents")
    
    print("\nServer-Side JavaScript Query Examples:")
    print("1. this.age > 30")
